const library: Record<TopicId, DailyItem[]> = {
  math: [
    { title: 'The 9 Trick', body: 'Any number multiplied by 9 has digits that sum to 9 (or a multiple of 9).', example: '9 × 8 = 72 → 7+2 = 9. Try 9 × 17 = 153 → 1+5+3 = 9.' },
    { title: 'Fibonacci in Nature', body: 'The Fibonacci sequence (1,1,2,3,5,8,13…) appears in sunflower seeds, pinecones, and galaxy spirals.', detail: 'Each number is the sum of the two before it, and the ratio between consecutive terms approaches φ ≈ 1.618, the Golden Ratio.' },
    { title: 'Why 0! = 1', body: 'Zero factorial equals 1 by definition — there is exactly one way to arrange zero objects: do nothing.', detail: 'It also makes combinatorics formulas work consistently, e.g. choosing 0 items from n: C(n,0) = n!/0!·n! = 1.' },
    { title: 'Lightning Fast Squaring', body: 'To square any number ending in 5: multiply the leading digit(s) by itself+1, then append 25.', example: '35² → 3×4 = 12, append 25 → 1225. Check: 35×35 = 1225 ✓' },
    { title: 'The Birthday Problem', body: 'In a room of just 23 people there is a 50% chance two share a birthday. With 70 people it\'s 99.9%.', detail: 'Our brains underestimate because we think linearly, but comparisons grow quadratically with each new person added.' },
    { title: 'Infinity Types', body: 'Not all infinities are equal. The set of real numbers is provably larger than the set of whole numbers, even though both are infinite.', detail: 'Georg Cantor\'s diagonal argument (1891) showed you cannot list all real numbers — some infinities are "uncountably" larger.' },
    { title: 'Pi Never Repeats', body: 'π (3.14159…) is irrational — its decimal expansion never terminates and never repeats. We have computed over 100 trillion digits.', detail: 'Despite this, 39 decimal places of π is enough to calculate the circumference of the observable universe to within one hydrogen atom.' },
    { title: 'The Rule of 72', body: 'Divide 72 by an annual interest rate to estimate how many years it takes to double your money.', example: 'At 6% interest: 72 ÷ 6 = 12 years to double. At 9%: just 8 years.' },
    { title: 'Prime Numbers are Infinite', body: 'Euclid proved around 300 BCE that there are infinitely many prime numbers. His proof takes just three lines.', detail: 'Assume a finite list of primes. Multiply them all and add 1. The result is either prime or divisible by a prime not in your list — contradiction.' },
    { title: 'The Monty Hall Problem', body: 'Switching doors after a goat is revealed gives a 2/3 chance of winning the car. Staying gives only 1/3.', detail: 'This counterintuitive result baffled thousands of mathematicians when Marilyn vos Savant published it in 1990.' },
    { title: 'Benford\'s Law', body: 'In naturally occurring datasets, the leading digit is 1 about 30% of the time, not the expected 11%.', detail: 'This law is used to detect financial fraud — fabricated numbers don\'t follow it because people choose digits "too evenly."' },
    { title: 'The Königsberg Bridge Problem', body: 'In 1736 Euler proved it\'s impossible to walk across all 7 bridges of Königsberg exactly once — founding graph theory in the process.', detail: 'He showed that for such a walk to exist, at most two "nodes" (landmasses) can have an odd number of connections.' },
    { title: 'Casting Out Nines', body: 'You can check multiplication by summing each number\'s digits down to a single digit and comparing products.', example: '123 × 456 = 56,088. Check: (1+2+3)=6, (4+5+6)=6, 6×6=36→3+6=9. Sum of 56088: 5+6+0+8+8=27→9 ✓' },
    { title: 'The Four Color Theorem', body: 'Any map can be colored with only 4 colors such that no two adjacent regions share a color.', detail: 'Proved in 1976, it was the first major theorem verified with computer assistance — checking over 1,800 cases automatically.' },
    { title: 'Gauss\'s Schoolboy Trick', body: 'To sum integers from 1 to n: n × (n+1) ÷ 2.', example: '1+2+…+100 = 100×101÷2 = 5,050. Young Gauss supposedly solved this in seconds when his teacher assigned it as busywork.' },
    { title: 'The Basel Problem', body: 'The sum of 1/n² for all positive integers n equals exactly π²/6 ≈ 1.6449. Euler proved this in 1734.', detail: 'This surprising appearance of π in a sum that has nothing to do with circles shocked mathematicians of the era.' },
    { title: 'Imaginary Numbers are Real', body: 'The imaginary unit i = √(-1) seems fictional, but it\'s essential for describing electrical circuits, quantum mechanics, and signal processing.', detail: 'Every smartphone chip uses complex numbers in its signal processing algorithms.' },
    { title: 'The Pigeonhole Principle', body: 'If you have n+1 items in n containers, at least one container must have 2+ items.', example: 'In any group of 13 people, at least two were born in the same month. In London, at least two people have the exact same number of hairs.' },
    { title: 'Pascal\'s Triangle Hides Everything', body: 'Pascal\'s triangle contains the Fibonacci sequence, powers of 2, powers of 11, binomial coefficients, and fractal patterns.', detail: 'Highlight every odd number in Pascal\'s triangle and you get the Sierpiński triangle fractal.' },
    { title: 'A Googol vs The Universe', body: 'A googol is 10¹⁰⁰. The estimated number of atoms in the observable universe is only about 10⁸⁰ — far smaller than a googol.', detail: 'A googolplex (10^googol) couldn\'t be written out even if every atom in the universe were a digit.' },
  ],

  vocab: [
    { title: 'Sonder', body: 'The realization that each passerby has a life as vivid and complex as your own.', example: '"She felt a wave of sonder watching the crowd from the café window."' },
    { title: 'Ephemeral', body: '(adj.) Lasting for a very short time; transitory.', example: '"The cherry blossoms are ephemeral — here for a week, then gone." From Greek ephēmeros, "lasting a day."' },
    { title: 'Petrichor', body: 'The pleasant earthy smell produced when rain falls on dry soil.', detail: 'From Greek petra (stone) + ichor (the fluid in the veins of the gods). Named by scientists Isabel Joy Bear and Richard Thomas in 1964.' },
    { title: 'Liminal', body: '(adj.) Occupying a transitional or uncertain stage between two states.', example: '"Graduation is a liminal moment — you\'re no longer a student but not yet a professional."' },
    { title: 'Hiraeth', body: 'A Welsh word with no English equivalent: a longing for home, a place you can\'t return to, or perhaps never was.', detail: 'Often described as a mixture of homesickness, grief, and nostalgia all in one feeling.' },
    { title: 'Serendipity', body: 'Finding something good without looking for it; a happy accident.', example: '"By pure serendipity, she sat next to her future business partner on a flight to Tokyo." Coined by Horace Walpole in 1754.' },
    { title: 'Taciturn', body: '(adj.) Reserved or uncommunicative in speech; saying little.', example: '"The taciturn detective spoke only when the answer mattered."' },
    { title: 'Mellifluous', body: '(adj.) Sweet or musical; pleasant to hear.', example: '"Her mellifluous voice could calm any room." From Latin mel (honey) + fluere (to flow).' },
    { title: 'Recondite', body: '(adj.) Not known by many; obscure; abstruse.', example: '"His lectures were filled with recondite references that only specialists understood."' },
    { title: 'Schadenfreude', body: 'Pleasure derived from another\'s misfortune.', detail: 'A German compound: Schaden (harm) + Freude (joy). English has no single word for this — proof that every language captures something unique.' },
    { title: 'Perspicacious', body: '(adj.) Having a ready insight; shrewd; having a clear mind.', example: '"Her perspicacious analysis saved the company from a costly mistake."' },
    { title: 'Logophile', body: 'A lover of words.', detail: 'From Greek logos (word) + philos (loving). If you\'re enjoying this daily vocab, you might be one.' },
    { title: 'Sesquipedalian', body: '(adj.) Long-worded; given to using long words.', detail: 'Irony: "sesquipedalian" is itself a very long word. From Latin sesquipedalis, "a foot and a half long."' },
    { title: 'Solipsism', body: 'The philosophical idea that only one\'s own mind is sure to exist; the self is all that can be known.', example: 'Used colloquially to describe someone absorbed only in their own world.' },
    { title: 'Inchoate', body: '(adj.) Just begun and not fully formed; undeveloped.', example: '"She had an inchoate idea that would eventually become a bestselling novel."' },
    { title: 'Defenestration', body: 'The act of throwing someone out of a window.', detail: 'From Latin fenestra (window). The Defenestration of Prague (1618) sparked the Thirty Years\' War. History\'s most dramatic word origin.' },
    { title: 'Vellichor', body: 'The strange wistfulness of used bookshops.', detail: 'Another invented word from the Dictionary of Obscure Sorrows — the feeling that all those books carry the weight of lives already lived.' },
    { title: 'Pulchritudinous', body: '(adj.) Beautiful.', detail: 'Widely considered the ugliest-sounding word meaning beautiful in English. A perfect paradox.' },
    { title: 'Obstreperous', body: '(adj.) Noisy and difficult to control.', example: '"The obstreperous crowd refused to let the speaker finish."' },
    { title: 'Limerence', body: 'The involuntary state of intense infatuation with another person, including intrusive thoughts and longing.', detail: 'Coined by psychologist Dorothy Tennov in 1979 — distinct from love in that it\'s one-sided obsession rather than mutual connection.' },
  ],

  funfacts: [
    { title: 'Honey Never Expires', body: 'Archaeologists have found 3,000-year-old honey in Egyptian tombs that was still perfectly edible.', detail: 'Honey\'s low moisture content, acidic pH, and natural hydrogen peroxide make it inhospitable to bacteria indefinitely.' },
    { title: 'A Day on Venus is Longer Than Its Year', body: 'Venus rotates so slowly that one Venusian day (243 Earth days) is longer than its year (225 Earth days).', detail: 'It also rotates backwards — if you could stand on Venus, the Sun would rise in the west and set in the east.' },
    { title: 'Octopuses Have Three Hearts', body: 'Two pump blood to the gills; one pumps it to the rest of the body. When an octopus swims, the main heart stops — making them tire easily.', detail: 'Their blood is blue because it uses copper-based hemocyanin instead of iron-based hemoglobin.' },
    { title: 'The Oxford Comma Once Cost Millions', body: 'In 2018, dairy drivers in Maine won a $5 million lawsuit because the absence of an Oxford comma made overtime exemptions ambiguous in their contract.', detail: 'Grammar has never been more expensive.' },
    { title: 'Cleopatra Lived Closer to the Moon Landing Than to the Building of the Pyramids', body: 'Cleopatra lived around 30 BCE. The Great Pyramid was built ~2560 BCE (2,500 years before her). The Moon landing was 1969 — only 2,000 years after her.', detail: 'Time perspective is consistently our biggest blind spot.' },
    { title: 'You Are Never More Than 6 Feet From a Spider', body: 'In most inhabited areas of the world, spiders are so numerous you\'re statistically within 2 meters of one at nearly all times.', detail: 'Globally, spiders consume an estimated 400–800 million tons of prey per year — more than the entire weight of humanity.' },
    { title: 'The Eiffel Tower Grows in Summer', body: 'The iron structure expands in heat and can grow up to 15 cm (6 inches) taller on the hottest days.', detail: 'Thermal expansion is why bridges have gaps — to prevent buckling as metal expands and contracts seasonally.' },
    { title: 'Nintendo Was Founded in 1889', body: 'Nintendo started as a playing card company in Kyoto, Japan — 80 years before it entered electronics.', detail: 'The name roughly translates to "leave luck to heaven." They still sell playing cards today.' },
    { title: 'The Human Body Contains Stardust', body: 'About 65% of your body is oxygen, 18% carbon — elements forged in the cores of dying stars billions of years ago.', detail: 'As Carl Sagan said: "We are a way for the cosmos to know itself."' },
    { title: 'A Group of Flamingos is Called a Flamboyance', body: 'Other great collective nouns: a murder of crows, a parliament of owls, a conspiracy of lemurs, an ambush of tigers.', detail: 'Flamingos get their pink color from carotenoid pigments in the algae and shrimp they eat. Born white, they turn pink in captivity too — if fed the right diet.' },
    { title: 'The Shortest War in History Lasted 38 Minutes', body: 'The Anglo-Zanzibar War of 1896 began at 9:02 AM and ended at 9:40 AM when the Sultan\'s palace was shelled.', detail: 'Zanzibar unconditionally surrendered. Casualties: ~500 on the Zanzibar side, one British sailor wounded.' },
    { title: 'Hot Water Freezes Faster Than Cold Water', body: 'The Mpemba Effect: under certain conditions, hot water will freeze before an equal amount of cold water.', detail: 'First documented by student Erasto Mpemba in 1963 — his physics teacher said he was wrong, but he was right. The exact mechanism is still debated.' },
    { title: 'Maine and Alaska Share No Borders With Other U.S. States', body: 'Maine borders only New Hampshire. Alaska borders only Canada. They are the only two U.S. states touching just one other state or country.', detail: 'This makes Alaska both the northernmost, westernmost, AND easternmost state — it crosses the 180° meridian.' },
    { title: 'Sharks Are Older Than Trees', body: 'Sharks have existed for ~450 million years. Trees appeared ~350 million years ago. Sharks saw the first forests grow.', detail: 'Sharks have survived all five mass extinctions, including the one that killed the dinosaurs.' },
    { title: 'There Are More Possible Games of Chess Than Atoms in the Universe', body: 'The number of possible chess games is estimated at 10¹²⁰ (Shannon Number). Observable universe atoms: ~10⁸⁰.', detail: 'This is why computers can\'t brute-force chess — they use evaluation functions and pruning to narrow the search.' },
    { title: 'The Word "Salary" Comes From Salt', body: 'Roman soldiers were sometimes paid in salt (Latin: sal), making it one of history\'s first currencies.', detail: 'Salt was revolutionary — the only way to preserve meat before refrigeration. It built and destroyed empires.' },
    { title: 'Bananas Are Berries; Strawberries Are Not', body: 'Botanically, a berry develops from a single flower with one ovary. Bananas qualify. Strawberries, raspberries, and blackberries do not.', detail: 'Avocados, kiwis, and watermelons are also technically berries. Peanuts are legumes. Almonds are drupes, not nuts.' },
    { title: 'The Great Wall of China Cannot Be Seen From Space', body: 'This is a persistent myth. The wall is wide enough to walk on but far too narrow to be seen from low Earth orbit without a camera zoom.', detail: 'Chinese astronaut Yang Liwei confirmed he couldn\'t see it during his 2003 space flight.' },
    { title: 'A Bolt of Lightning Contains About 1 Billion Joules', body: 'That\'s enough to toast 100,000 slices of bread — yet 99% is lost as heat, light, and sound. Only ~1 billion joules actually reach the ground.', detail: 'The average lightning bolt lasts 0.2 seconds and reaches 30,000 Kelvin — five times hotter than the Sun\'s surface.' },
    { title: 'The Inventor of the Frisbee Became a Frisbee', body: 'Walter Morrison, who sold the Frisbee concept to Wham-O in 1957, had his ashes mixed into memorial Frisbees after his death in 2010.', detail: 'The name "Frisbee" came from Frisbie Pie Company tins that college students tossed in the 1940s.' },
  ],

  science: [
    { title: 'You Are Mostly Empty Space', body: 'If you removed all empty space from every atom in a human body, the remaining matter would fit in a sugar cube — but weigh 1,000 kg.', detail: 'Atoms are 99.9999999% empty space. What we perceive as solid is electromagnetic force between particles, not actual touching.' },
    { title: 'Your Brain Uses 20% of Your Body\'s Energy', body: 'The brain is only ~2% of body weight but consumes 20% of energy and oxygen. It burns roughly 0.1 calorie per minute just existing.', detail: 'Thinking harder uses only slightly more energy — deep concentration increases consumption by about 1%. The myth of "10% of the brain" has no scientific basis.' },
    { title: 'Water Can Boil and Freeze Simultaneously', body: 'At the "triple point" (0.01°C, 611.7 Pa), water can exist simultaneously as solid, liquid, and gas.', detail: 'This precise point is used to calibrate thermometers. It\'s one of the most reproducible physical phenomena in nature.' },
    { title: 'Sound Can\'t Travel in Space — But Light Can', body: 'Sound needs a medium (air, water, solid) to propagate. Space is a near-vacuum. Explosions in space are completely silent.', detail: 'Light is an electromagnetic wave — it needs no medium and can travel through a perfect vacuum at 299,792,458 m/s.' },
    { title: 'The Smell of Rain is Geosmin', body: 'Petrichor\'s main compound is geosmin, produced by soil bacteria (Streptomyces). Humans can detect it at concentrations as low as 5 parts per trillion.', detail: 'We evolved extreme sensitivity to geosmin because rain meant water and survival for our ancestors. It\'s 200,000x more detectable than sharks smell blood.' },
    { title: 'Quantum Entanglement is Real', body: 'Two particles can be "entangled" so that measuring one instantly determines the state of the other — no matter the distance.', detail: 'Einstein called it "spooky action at a distance" and thought it was an error. He was wrong. The 2022 Nobel Prize in Physics went to proving it experimentally.' },
    { title: 'Trees Communicate Through Fungi', body: 'Forests are connected by a "Wood Wide Web" — a network of mycorrhizal fungi through which trees share nutrients, water, and chemical signals.', detail: 'Mother trees preferentially send carbon to their seedlings through this network. Dying trees have been observed sending resource pulses to neighbors.' },
    { title: 'Your DNA Would Stretch 67 Billion Miles If Uncoiled', body: 'Each human cell contains ~6 feet (2 meters) of DNA. Multiply by 37 trillion cells and you get a strand that would reach the Sun and back over 350 times.', detail: 'Proteins called histones spool the DNA into a compact structure smaller than a grain of sand. The packing ratio is 1:40,000.' },
    { title: 'Glass is Not a Slow-Moving Liquid', body: 'Old cathedral windows are thicker at the bottom because of imperfect medieval manufacturing, not because glass "flows" over centuries.', detail: 'Glass is an amorphous solid — its atoms lack the long-range order of crystals. At room temperature it would take longer than the age of the universe to flow.' },
    { title: 'The Mantis Shrimp Can Punch at 50 mph', body: 'Mantis shrimp strike with the force of a bullet and can shatter aquarium glass. The strike lasts only 1/3,000th of a second.', detail: 'The impact creates cavitation bubbles that collapse with a flash of light (sonoluminescence) and a second shockwave — essentially punching twice.' },
    { title: 'Every Second, the Sun Converts 4 Million Tons Into Energy', body: 'Nuclear fusion in the Sun\'s core converts ~4 million metric tons of mass into energy per second via E=mc².', detail: 'The Sun loses 4 million tons per second yet has enough fuel for another 5 billion years. It has burned through about half its hydrogen supply.' },
    { title: 'Cold Water Conducts Electricity Better Than Hot', body: 'Electrical conductivity in water decreases as temperature rises because ions move faster and collide more, impeding flow.', detail: 'Pure distilled water is actually a very poor conductor — it\'s the dissolved salts and minerals that carry current.' },
    { title: 'Your Gut Has Its Own Nervous System', body: 'The enteric nervous system contains 100–500 million neurons — more than the spinal cord. The gut can function independently of the brain.', detail: '90% of the vagus nerve\'s signals travel from gut to brain, not the other way. Your gut genuinely influences your mood and decisions.' },
    { title: 'Neutron Stars Are Mind-Bendingly Dense', body: 'A teaspoon of neutron star material would weigh roughly 10 million tons.', detail: 'Neutron stars form when a massive star collapses. The entire mass of a city-sized object (20 km diameter) is compressed — gravity so strong it warps spacetime.' },
    { title: 'Photons Take 100,000 Years to Escape the Sun', body: 'Sunlight takes 8 minutes to travel from the Sun\'s surface to Earth. But the same photons took ~100,000 years to travel from the core to the surface.', detail: 'The core is so dense that photons are constantly absorbed and re-emitted, zigzagging in a random walk outward at an effective speed of centimeters per year.' },
    { title: 'Bees Can Recognize Human Faces', body: 'Honeybees use the same pattern recognition system humans use — called "configural processing" — to distinguish individual human faces.', detail: 'They can be trained to associate specific faces with rewards. This ability likely evolved to help them navigate complex flower patterns.' },
    { title: 'The Speed of Light Varies by Medium', body: 'Light travels at c=299,792,458 m/s only in a vacuum. In glass it slows to ~200,000 km/s. In water, ~225,000 km/s.', detail: 'This slowing is the refractive index. Cherenkov radiation (the blue glow in nuclear reactors) occurs when particles travel faster than light does in that medium.' },
    { title: 'There Are More Trees Than Stars in the Milky Way', body: 'Earth has ~3 trillion trees. The Milky Way has ~200–400 billion stars. Trees win by a factor of 7–15.', detail: 'Humanity has cut down roughly half of all trees since the start of civilization. We plant ~15 billion per year but cut ~46 billion.' },
    { title: 'Viruses Outnumber Everything Else on Earth', body: 'There are an estimated 10³¹ viruses on Earth — more than all other life combined, and more than stars in the observable universe.', detail: 'If all Earth\'s viruses were lined up end to end, the chain would extend 100 million light-years. Most viruses infect bacteria, not animals.' },
    { title: 'Time Passes Faster at Higher Altitudes', body: 'Gravity slows time (gravitational time dilation). Clocks on GPS satellites run ~38 microseconds faster per day than on Earth — and must be corrected.', detail: 'This effect was predicted by Einstein in 1915 and confirmed experimentally. Without the correction, GPS would drift ~10 km per day.' },
  ],

  history: [
    { title: 'The Library of Alexandria Wasn\'t Burned Down Once', body: 'The Library of Alexandria declined over centuries through multiple fires, budget cuts, and political shifts — not one dramatic burning.', detail: 'Julius Caesar accidentally burned part of it in 48 BCE. But it was still partially functional 400 years later. The "single fire" story is a myth.' },
    { title: 'Napoleon Was Not Especially Short', body: 'Napoleon stood about 5\'7" (170 cm) — average height for a Frenchman of his era. The "short" myth originated from British propaganda and a unit conversion error.', detail: 'He was listed as 5\'2" in French units (pouce) — which are longer than British inches. His nickname "le petit caporal" referred to affection, not stature.' },
    { title: 'The Roman Empire Never Really Fell', body: 'The Eastern Roman Empire (Byzantine Empire) continued for nearly 1,000 years after 476 CE, falling to the Ottomans only in 1453.', detail: 'The Byzantines called themselves Romans and used Roman law. The Ottoman Sultan then used the title "Caesar of Rome." The fall of Rome was a very slow process.' },
    { title: 'The Fastest Soldiers in History Carried Phones', body: 'During WWII, carrier pigeons delivered messages more reliably than early radio in battlefield conditions. Pigeon Cher Ami delivered 12 critical messages and was awarded the Croix de Guerre.', detail: 'The last military carrier pigeon service was retired by India\'s Orissa police in 2004.' },
    { title: 'Coca-Cola Was Originally Green', body: 'Early glass bottles gave Coca-Cola a green tint. The drink was also marketed as a "nerve tonic" containing cocaine from coca leaves until 1903.', detail: 'The "de-cocainized" leaves are still used as a flavoring. Coca-Cola still imports about 100 metric tons of coca leaves per year, processed in New Jersey.' },
    { title: 'The Great Fire of London Killed Almost Nobody', body: 'The 1666 Great Fire destroyed 13,200 houses and 87 churches — yet only 6 confirmed deaths are recorded.', detail: 'The city\'s population of ~80,000 had time to evacuate. The fire ironically ended a plague outbreak by burning the rat-infested slums where it thrived.' },
    { title: 'The First Computer Bug Was an Actual Bug', body: 'In 1947, Grace Hopper\'s team at Harvard found a moth trapped in relay 70 of the Harvard Mark II computer, causing errors.', detail: 'Hopper taped the moth into the logbook with the note "First actual case of bug being found." The logbook is at the Smithsonian Institution.' },
    { title: 'The Mongol Empire Was the World\'s Largest Contiguous Land Empire', body: 'At its peak in 1279, the Mongol Empire covered 24 million km² — about the size of Africa — and controlled 25% of the world\'s population.', detail: 'Under Pax Mongolica, trade along the Silk Road flourished. The Black Death likely spread via Mongol trade routes from Asia to Europe.' },
    { title: 'Oxford University Is Older Than the Aztec Empire', body: 'Teaching at Oxford began around 1096-1167 CE. The Aztec Empire was founded ~1428 CE. Oxford is at least 260 years older.', detail: 'Oxford is also older than the construction of Windsor Castle, the invention of the mechanical clock, and the Black Death.' },
    { title: 'Einstein Was Offered the Presidency of Israel', body: 'In 1952, Einstein was asked to become Israel\'s second president after Chaim Weizmann\'s death. He declined, saying he lacked the natural aptitude for people and politics.', detail: '"I am deeply moved by the offer, but I feel I am not suited and I am not able to perform the duties attached to high office."' },
    { title: 'The Last Confederate General Surrendered in 1865 — in Liverpool', body: 'CSS Shenandoah was a Confederate warship that continued raiding Union ships until August 1865 — four months after the war ended — because the crew hadn\'t heard the news.', detail: 'Commander James Waddell struck the Confederate flag and surrendered to British authorities in Liverpool on November 6, 1865, the last Confederate officer to do so.' },
    { title: 'The 100 Years\' War Lasted 116 Years', body: 'The conflict between England and France ran from 1337 to 1453 — 116 years. It was actually multiple wars with long truces between them.', detail: 'The war produced Joan of Arc, permanently ended English claims to France, and helped shape modern national identity in both countries.' },
    { title: 'Nikola Tesla Offered to Destroy the Earth — for a Price', body: 'Tesla claimed his earthquake machine (a mechanical oscillator) could theoretically resonate at Earth\'s frequency and trigger catastrophic earthquakes.', detail: 'He once activated it in his lab, causing his building to shake and nearby buildings to rattle, panicking the neighborhood, before smashing it with a hammer.' },
    { title: 'Alaska Was Purchased for 2 Cents an Acre', body: 'The U.S. bought Alaska from Russia in 1867 for $7.2 million — about $0.02 per acre. The press called it "Seward\'s Folly" and "Seward\'s Icebox."', detail: 'Russia feared losing it to Britain anyway. Alaska has since yielded trillions of dollars in oil, gas, gold, fish, and strategic military value.' },
    { title: 'Ancient Romans Used Crushed Mouse Brains as Toothpaste', body: 'Roman dental hygiene included powders made from mouse brain, rabbit head, and lizard liver. Also charcoal, crushed oyster shells, and urine.', detail: 'Urine (ammonia) was actually an effective cleaning agent and was used as mouthwash in ancient Rome and still marketed in 18th-century Europe.' },
    { title: 'The First Webcam Watched a Coffee Pot', body: 'In 1991, Cambridge University researchers set up a camera aimed at their communal coffee pot to avoid wasted trips when it was empty.', detail: 'It became the first public webcam when connected to the internet in 1993. The pot sold on eBay in 2001 for £3,350. It is now in a German tech museum.' },
    { title: 'Woolly Mammoths Lived When the Great Pyramid Was Being Built', body: 'The last population of woolly mammoths died on Wrangel Island (Russia) around 1650 BCE. The Great Pyramid was completed ~2560 BCE.', detail: 'For 900 years, pharaohs and woolly mammoths coexisted on Earth. The mammoths outlasted the entire Old Kingdom of Egypt.' },
    { title: 'The Soviet Union and USA Almost Accidentally Started WWIII in 1983', body: 'On September 26, 1983, Soviet satellite systems falsely detected 5 US nuclear missiles inbound. Lt. Colonel Stanislav Petrov decided it was a malfunction and did not report it up the chain.', detail: 'His decision — to report a "system malfunction" instead of a confirmed US attack — likely prevented a retaliatory nuclear launch. He was initially reprimanded, then later honored.' },
    { title: 'Ancient Egyptians Shaved Eyebrows When a Cat Died', body: 'Cats were sacred in ancient Egypt. When a household cat died, family members shaved their eyebrows as a sign of mourning.', detail: 'Herodotus recorded this in ~450 BCE. Killing a cat — even accidentally — was punishable by death. Egyptians would die in building fires rather than leave cats behind.' },
    { title: 'LEGO Is the World\'s Largest Tire Manufacturer', body: 'LEGO produces about 318 million tiny rubber tires per year for its toy sets — more than any other company makes real tires.', detail: 'LEGO was founded by Ole Kirk Christiansen in 1932. The name combines Danish "leg godt" (play well). The interlocking brick was patented in 1958.' },
  ],

  philosophy: [
    { title: 'Stoicism\'s Core Practice', body: '"Make the best use of what is in your power, and take the rest as it happens." — Epictetus', detail: 'Stoics divided the world into two categories: what is "up to us" (our thoughts, judgments, actions) and what is not. Freedom comes from caring only about the former.' },
    { title: 'Socrates on Knowledge', body: '"I know that I know nothing." — Socrates (paraphrased)', detail: 'The original Greek is more nuanced: recognizing ignorance is the beginning of wisdom. The "Socratic method" of questioning to expose hidden assumptions changed education forever.' },
    { title: 'Pascal\'s Wager', body: 'If God exists and you believe, infinite gain. If God doesn\'t exist and you believe, finite loss. Logic therefore suggests belief.', detail: 'Critics (including Voltaire) noted this ignores which God to believe in and whether God would accept insincere belief. But it pioneered formal decision theory.' },
    { title: 'The Ship of Theseus', body: 'If you replace every plank of a ship over time, is it still the same ship? If not, at what point did it change?', detail: 'Applied to humans: your cells replace themselves roughly every 7 years. Your neurons largely don\'t. "You" at 10 and 40 share almost no atoms — yet continuous memory persists.' },
    { title: 'Plato\'s Cave', body: 'Prisoners chained in a cave see only shadows on a wall and mistake them for reality. Freedom means turning to see the true light.', detail: 'The allegory asks: could our entire reality be a projection? Plato used it to argue philosophers — who turn toward Truth — should govern society.' },
    { title: 'Kant\'s Categorical Imperative', body: '"Act only according to that maxim whereby you can at the same time will that it should become a universal law."', detail: 'In plain English: before acting, ask "what if everyone did this?" If the world breaks down, don\'t do it. This is the foundation of modern duty-based ethics.' },
    { title: 'Nietzsche\'s Eternal Return', body: 'What if you had to live your exact life — every joy and every suffering — infinitely repeated? Would you embrace it?', detail: 'Nietzsche used it as a thought experiment, not a cosmological claim. It\'s a test: if you wouldn\'t want to repeat your life, you should change how you\'re living it.' },
    { title: 'Occam\'s Razor', body: 'When two explanations fit the evidence equally well, prefer the simpler one.', detail: 'Named for William of Ockham (1287–1347). Often misquoted — it doesn\'t say the simplest explanation is correct, only that unnecessary complexity should be cut away.' },
    { title: 'Camus on the Absurd', body: '"One must imagine Sisyphus happy." — Albert Camus', detail: 'The gods punished Sisyphus to push a boulder uphill forever, watching it roll down, forever. Camus argues life has no inherent meaning — but we can still choose to embrace it fully.' },
    { title: 'Hume\'s Is-Ought Problem', body: 'No "ought" (moral claim) can be logically derived from an "is" (factual claim) alone.', example: '"People are selfish by nature" (is) → "Therefore selfishness is okay" (ought). The jump is unjustified. Facts describe; they don\'t prescribe.' },
    { title: 'The Trolley Problem', body: 'A trolley will kill 5 people. You can pull a lever to divert it, killing 1 instead. Do you act?', detail: 'Variants: push someone in front to stop it; the one person is your child. Most people say "pull lever yes, push person no" — revealing we use different ethics for action vs. inaction.' },
    { title: 'Aristotle\'s Golden Mean', body: 'Virtue lies between two extremes of vice — deficiency and excess.', example: 'Courage is the mean between cowardice (deficiency) and recklessness (excess). Generosity lies between miserliness and wastefulness.' },
    { title: 'Descartes\' Cogito', body: '"I think, therefore I am." — René Descartes', detail: 'Descartes doubted everything, including his senses. But the very act of doubting proved he must exist — something must be doing the doubting. The one thing you can\'t doubt is your own existence as a thinking thing.' },
    { title: 'John Stuart Mill on Liberty', body: '"The only freedom which deserves the name is that of pursuing our own good in our own way."', detail: 'Mill\'s Harm Principle: society can only restrict individual freedom to prevent harm to others. Your freedom ends where someone else\'s begins.' },
    { title: 'The Veil of Ignorance', body: 'John Rawls asked: what social rules would you design if you didn\'t know what position you\'d occupy in society?', detail: 'Not knowing if you\'d be rich or poor, abled or disabled, any race — you\'d build the fairest possible system. This is the foundation of modern liberal political philosophy.' },
    { title: 'Zeno\'s Paradox of Motion', body: 'To travel anywhere, you must first cross half the distance. Then half of what remains. Then half again — infinitely. So how does motion ever complete?', detail: 'Resolved by calculus: an infinite series of finite numbers can sum to a finite total. But Zeno\'s question was actually prescient — motion in quantum mechanics is discrete, not continuous.' },
    { title: 'The Chinese Room', body: 'John Searle\'s thought experiment: a person who speaks no Chinese, following rules to respond to Chinese characters, passes a language test — but does not understand Chinese. Can computers truly "understand"?', detail: 'This remains the central debate in AI philosophy. Is GPT-style AI "understanding" language or just performing sophisticated Chinese Room operations?' },
    { title: 'Simone de Beauvoir on Freedom', body: '"One is not born, but rather becomes, a woman." — Simone de Beauvoir', detail: 'Her 1949 work The Second Sex argued gender is a social construction, not a biological destiny — foundational to modern feminism. She applied existentialism to show how women were defined by their relation to men.' },
    { title: 'The Paradox of Tolerance', body: 'Karl Popper: "Unlimited tolerance must lead to the disappearance of tolerance." If we extend tolerance to those who are intolerant, they will destroy tolerance.', detail: 'Therefore, a tolerant society must retain the right to not tolerate intolerance — not as a contradiction but as a self-defense mechanism for tolerance itself.' },
    { title: 'Confucius on Self-Improvement', body: '"The man who moves a mountain begins by carrying away small stones." — Confucius', detail: 'Confucian ethics emphasize continuous self-cultivation (修身, xiū shēn) as the foundation of everything — a good family, good governance, a good world.' },
  ],

  wellness: [
    { title: 'The 2-Minute Rule', body: 'If a task will take less than 2 minutes, do it immediately instead of scheduling it. The decision cost exceeds the doing cost.', detail: 'From David Allen\'s Getting Things Done. Reduces mental overhead and the pile of "tiny tasks" that accumulate into anxiety.' },
    { title: 'Sleep Is When Your Brain Washes Itself', body: 'The glymphatic system — your brain\'s waste-clearing mechanism — is nearly 10× more active during sleep. It flushes out proteins linked to Alzheimer\'s and depression.', detail: 'Even one night of poor sleep measurably increases beta-amyloid accumulation. Sleep is not downtime — it is essential biological maintenance.' },
    { title: 'Cold Exposure Boosts Dopamine 250%', body: 'A 20-second cold shower or cold plunge triggers a sustained dopamine release of 250% above baseline — lasting hours, not minutes.', detail: 'Unlike food or drugs, this dopamine doesn\'t cause a crash. Dopamine is a molecule of motivation and focus, not just pleasure.' },
    { title: 'You Can Only Focus Deeply for ~4 Hours Per Day', body: 'Research on elite performers shows most people have a biological ceiling of ~4 hours of genuine deep work per day. Beyond that, performance degrades significantly.', detail: 'Cal Newport and Anders Ericsson both documented this. The implication: protect your mornings, limit shallow tasks, and stop feeling guilty for "not working more."' },
    { title: 'Walking 11 Minutes a Day Cuts Mortality Risk 23%', body: 'A 2023 study in the British Journal of Sports Medicine found just 11 minutes of moderate-intensity exercise per day reduces all-cause mortality risk by ~23%.', detail: 'The relationship between exercise and mortality isn\'t linear — the biggest gains come from going from zero to moderate. Elite athletes get diminishing returns beyond that.' },
    { title: 'Gratitude Rewires the Brain', body: 'Consistently writing 3 things you\'re grateful for each day measurably increases gray matter in the medial prefrontal cortex — the area associated with positive emotion and resilience.', detail: 'Studies show effects begin after just 3 weeks. The key: be specific ("my friend texted to check in") not generic ("my health"). Specificity requires genuine recall.' },
    { title: 'The HALT Check', body: 'Before reacting emotionally, ask: Am I Hungry, Angry, Lonely, or Tired? These four states account for most impulsive decisions and overreactions.', detail: 'HALT originated in addiction recovery but applies broadly. Identifying the biological state lets you address it rather than misattribute it.' },
    { title: 'Nature Reduces Cortisol in 20 Minutes', body: 'Just 20 minutes in a natural setting measurably reduces cortisol (the primary stress hormone) — even in urban parks, not just wilderness.', detail: 'The effect is amplified when you\'re not scrolling your phone. Researchers call this "nature exposure" and it requires surprisingly little wilderness to be effective.' },
    { title: 'Social Connection Is as Important as Exercise', body: 'Loneliness is as harmful to health as smoking 15 cigarettes per day. Strong social ties increase longevity more than diet, exercise, or wealth combined.', detail: 'The Harvard Study of Adult Development (80+ years of data) found that the quality of close relationships at age 50 was the single strongest predictor of health at 80.' },
    { title: 'The 5-4-3-2-1 Grounding Technique', body: 'To interrupt anxiety or panic: name 5 things you can see, 4 you can touch, 3 you can hear, 2 you can smell, 1 you can taste.', detail: 'This forces the brain out of the prefrontal cortex (future-worrying) and into the sensorium (present moment). Used by therapists, military, and athletes.' },
    { title: 'Hydration Before Coffee', body: 'Cortisol peaks within 30–60 minutes of waking. Caffeine during this window builds tolerance, not energy. Wait 90 minutes; drink 500ml water first.', detail: 'Sleep dehydrates you by 0.5–1 liter. Rehydrating first thing improves cognitive performance more than coffee consumed immediately upon waking.' },
    { title: 'Your Attention Is Your Life', body: '"Your life is the sum of what you focus on." What you give attention to grows. What you ignore atrophies — including relationships, skills, and emotions.', detail: 'The average person will spend 7 years of their life on social media. Treating attention as a finite, precious resource rather than an infinite tap is a foundational life skill.' },
    { title: 'Progressive Muscle Relaxation Reduces Anxiety Faster Than Breathing', body: 'Tensing and releasing muscle groups in sequence (feet → head, 5s each) activates the parasympathetic nervous system faster than controlled breathing alone.', detail: 'Developed by Edmund Jacobson in 1920. Takes ~10 minutes. Combines well with breathing: tense on inhale, release on exhale.' },
    { title: 'Decision Fatigue is Real', body: 'Every decision you make depletes the same mental resource — from "what to eat" to "should I fire this employee." By evening, decision quality measurably drops.', detail: 'This is why judges grant parole more in the morning, and why Obama and Zuckerberg famously reduced clothing decisions. Protect high-stakes decisions for earlier in the day.' },
    { title: 'Reading Fiction Builds Empathy', body: 'MRI studies show reading literary fiction activates the same neural networks as actually experiencing the events described — including theory-of-mind (understanding others\' mental states).', detail: 'Effects are measurable after reading a single short story. Genre fiction shows weaker effects, likely because character psychology is less complex.' },
    { title: 'Napping for 26 Minutes Improves Performance 34%', body: 'NASA research on military pilots found a 26-minute nap improved performance by 34% and alertness by 100%. The specific duration avoids deep sleep (which causes grogginess).', detail: 'Set an alarm. Lie down immediately. Even if you don\'t sleep, the horizontal rest and eye closure provide benefit. Caffeine before the nap maximizes the effect (it takes ~30 min to activate).' },
    { title: 'You Are What You Repeatedly Do', body: '"We are what we repeatedly do. Excellence, then, is not an act, but a habit." — Will Durant (summarizing Aristotle)', detail: 'The neuroscience: repeated behaviors myelinate neural pathways — literally making them faster and more automatic. Identity follows behavior, not vice versa. Act first; become second.' },
    { title: 'Sunlight Before Screens Sets Your Circadian Rhythm', body: 'Getting bright outdoor light within the first 30–60 minutes after waking anchors your cortisol/melatonin cycle for the whole day, improving energy, mood, and sleep.', detail: 'Indoor light is 100–200 lux. Outdoor light is 10,000–100,000 lux. Your circadian clock needs this signal to calibrate. Even on cloudy days, outdoor light far exceeds indoor.' },
    { title: 'The Best Exercise Is the One You\'ll Actually Do', body: 'Consistency beats optimization. A "suboptimal" workout performed 4× a week destroys a "perfect" workout you skip because it\'s too hard or too long.', detail: 'Adherence is the single largest factor in fitness outcomes. Finding enjoyment and social elements in exercise dramatically outperforms any training program followed reluctantly.' },
    { title: 'Journaling for 20 Minutes Reduces Trauma Symptoms', body: 'Psychologist James Pennebaker found that writing about traumatic events for 20 minutes over 4 days measurably reduced medical visits, improved immune function, and reduced PTSD symptoms.', detail: 'The mechanism: translating emotion into language reduces amygdala activation. You don\'t need to share it. The act of structuring experience into words is itself therapeutic.' },
  ],

  tech: [
    { title: 'Your Phone Is a Million Times Faster Than Apollo 11', body: 'The Apollo Guidance Computer ran at 0.043 MHz with 4 KB RAM. A modern iPhone runs at ~3 GHz with 6 GB RAM — roughly a million times more powerful.', detail: 'Apollo used 4 KB of RAM to land humans on the moon. Your phone uses more processing power in one second than Apollo used in its entire mission.' },
    { title: 'The Internet Weighs About 50 Grams', body: 'All the electrons flowing through the internet\'s servers at any moment weigh an estimated 50 grams — about the weight of a strawberry.', detail: 'Calculated by physicist Russel Seitz using the mass of electrons in motion. The internet itself has no weight — only its electrical charge does.' },
    { title: 'The First Email Was Sent in 1971', body: 'Ray Tomlinson sent the first networked email in 1971 on ARPANET. He also invented the @ symbol convention for email addresses.', detail: 'He couldn\'t remember what the first email said — something like "QWERTYUIOP." The @ was chosen because it means "at" and didn\'t appear in any name.' },
    { title: 'HTTPS Protects Your Data With Math', body: 'HTTPS uses RSA or elliptic curve cryptography. Breaking a 2048-bit RSA key would take a classical computer longer than the age of the universe.', detail: 'Quantum computers (Shor\'s algorithm) could theoretically break RSA. This is why "post-quantum cryptography" is being standardized now — preparing for a future quantum threat.' },
    { title: 'Git Was Written in 10 Days', body: 'Linus Torvalds wrote Git in approximately 10 days in April 2005, after a fallout with the BitKeeper version control system.', detail: 'He named it "git" — British slang for a stupid, contemptible person — saying "I\'m an egotistical bastard, and I name all my projects after myself." (Linux being the first.)' },
    { title: 'The First Computer Virus Was Released in 1986', body: '"Brain" was written by two Pakistani brothers to protect their medical software from piracy. It spread via floppy disks and displayed their contact info.', detail: 'They offered to remove it if you called them. It was annoying but benign. The era of malicious viruses came years later, and they regret it deeply.' },
    { title: 'One Hour of YouTube Video Is Uploaded Every Second', body: 'As of 2024, users upload over 500 hours of video to YouTube every single minute — more than 30,000 hours per hour.', detail: 'If you tried to watch all YouTube content uploaded in one minute, it would take you 82 years. The total library is effectively unviewable by any single human.' },
    { title: 'TCP/IP Was Designed Around Nuclear Resilience', body: 'ARPANET (the internet\'s predecessor) was designed so that if any nodes were destroyed (say, by nuclear strike), packets would reroute automatically.', detail: 'This is why the internet is so hard to censor or shut down — it was literally designed to survive attacks by routing around damage.' },
    { title: 'JavaScript Was Written in 10 Days', body: 'Brendan Eich created JavaScript in May 1995 in just 10 days while at Netscape. It was originally called Mocha, then LiveScript, then JavaScript.', detail: 'The name change to JavaScript was a marketing move to capitalize on Java\'s popularity — they are completely unrelated languages. The rush shows: JS has many notorious quirks.' },
    { title: 'Your Password Is Probably Already Leaked', body: 'Over 10 billion unique username/password combinations have been collected in data breaches as of 2024. haveibeenpwned.com lets you check your email.', detail: 'Reusing passwords across sites is why single breaches cascade. A password manager generates and stores unique passwords per site — the single highest-impact security improvement most people can make.' },
    { title: 'The Cloud Is Just Someone Else\'s Computer', body: 'AWS, Azure, and Google Cloud together control ~65% of global cloud infrastructure. "The cloud" is primarily three companies\' data centers.', detail: 'AWS had a multi-hour outage in 2017 that took down Netflix, Slack, Imgur, and thousands of other services simultaneously — illustrating extreme concentration risk.' },
    { title: 'AI Models Don\'t Actually Understand Language', body: 'Large language models (like GPT) predict the statistically likely next token given context. They don\'t have beliefs, intentions, or understanding — they have patterns.', detail: 'Whether this is "real" intelligence is a genuine philosophical debate. But the practical output — reasoning, coding, writing — emerges from scale and architecture, not comprehension.' },
    { title: 'The First iPhone Had No App Store', body: 'The original iPhone (2007) ran only Apple\'s built-in apps. Steve Jobs initially opposed third-party apps. The App Store launched in 2008 with 500 apps.', detail: 'Today there are ~1.8 million iOS apps. The App Store generates more revenue per year than Hollywood box offices worldwide.' },
    { title: 'Wi-Fi Has a Speed Limit of Light', body: 'Wi-Fi radio waves travel at the speed of light, but actual data throughput is limited by protocol overhead, interference, encoding, and range — often 50-90% lower than advertised speeds.', detail: 'Wi-Fi 7 (802.11be) supports up to 46 Gbps theoretically. Real-world performance is typically 2-5 Gbps in ideal conditions. "Up to" in marketing means "theoretical maximum."' },
    { title: 'Linux Runs Almost Everything', body: 'Android (Linux), most web servers (Linux), all top 500 supercomputers (Linux), 96% of cloud infrastructure — Linux dominates everything except the desktop.', detail: 'Linus Torvalds started it as a hobby in 1991. "Just a hobby, won\'t be big and professional like gnu." It is now arguably the most important software ever written.' },
    { title: 'Moore\'s Law Is Slowing Down', body: 'Gordon Moore predicted in 1965 that transistor counts would double every ~2 years. This held for 50 years. TSMC\'s current 3nm chips pack 292 million transistors per mm².', detail: 'We\'re approaching physical limits — transistors are now ~10 atoms wide. The industry is shifting to 3D stacking, specialized chips (GPUs, NPUs), and quantum computing to continue performance gains.' },
    { title: 'The Y2K Bug Cost $300 Billion to Fix — and Worked', body: 'Programmers stored years as 2-digit numbers (99 for 1999). On Jan 1, 2000, "00" would read as 1900. ~$300 billion was spent globally on remediation.', detail: 'The near-absence of catastrophe on Y2K is proof the fixes worked, not proof it was overhyped. Systems that weren\'t fixed (e.g., some small plant control systems) did fail.' },
    { title: 'Bluetooth Is Named After a Viking King', body: 'Harald "Bluetooth" Gormsson united Danish tribes in the 10th century. The wireless standard (1994) was named for him — the idea being it would unite communication protocols.', detail: 'The Bluetooth logo is a runic monogram of his initials H (ᚼ) and B (ᛒ). It was intended as a temporary codename but stuck.' },
    { title: 'The First Spam Email Was Sent in 1978', body: 'Gary Thuerk sent an unsolicited email to 393 ARPANET users advertising Digital Equipment Corporation computers. The response was angry, but he made sales.', detail: 'He\'s called the "Father of Spam." His message was 6 hours premature (ARPANET system clock issue). Today ~85% of all email sent is spam — around 160 billion messages per day.' },
    { title: 'Quantum Computers Exist — But Can\'t Beat Normal Computers Yet', body: 'Google\'s Sycamore (2019) solved a specific problem in 200 seconds that would take classical computers 10,000 years. But the problem was specifically designed for quantum computers.', detail: 'No quantum computer has solved a useful real-world problem faster than classical computers. The hardware is extraordinarily fragile — qubits must be cooled to near absolute zero.' },
  ],
};

export function getDailyItem(topicId: TopicId): DailyItem {
  const items = library[topicId];
  const dayOfYear = Math.floor(Date.now() / 86_400_000); // days since epoch
  return items[dayOfYear % items.length];
}

export function getTodayKey(): string {
  return new Date().toISOString().split('T')[0];
}
